#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCoupons;
    vector<pair<string, string>> electronics, grocery, pharmacy, restaurant;

    regex validCodeRegex("^[a-zA-Z0-9_]+$");

    for (size_t i = 0; i < code.size(); ++i) {
        if (!isActive[i]) continue;
        if (code[i].empty()) continue;
        if (!regex_match(code[i], validCodeRegex)) continue;

        string bl = businessLine[i];
        if (bl == "electronics") {
            electronics.emplace_back(code[i], bl);
        } else if (bl == "grocery") {
