        return a.first < b.first;
    };

    sort(electronics.begin(), electronics.end(), cmp);
    sort(grocery.begin(), grocery.end(), cmp);
    sort(pharmacy.begin(), pharmacy.end(), cmp);
    sort(restaurant.begin(), restaurant.end(), cmp);

    for (const auto& p : electronics) {
        validCoupons.push_back(p.first);
